// Simple Chart implementation for demo purposes
window.Chart = function(ctx, config) {
    this.ctx = ctx;
    this.config = config;
    this.render = function() {
        // Simple line chart rendering
        const canvas = ctx;
        const context = canvas.getContext('2d');
        const data = config.data;
        const options = config.options || {};
        
        // Clear canvas
        context.clearRect(0, 0, canvas.width, canvas.height);
        
        // Draw simple line chart
        const dataset = data.datasets[0];
        const points = dataset.data;
        const labels = data.labels;
        const width = canvas.width;
        const height = canvas.height;
        const padding = 40;
        const graphWidth = width - padding * 2;
        const graphHeight = height - padding * 2;
        
        // Find min and max values
        const maxValue = Math.max(...points);
        const minValue = Math.min(...points);
        const valueRange = maxValue - minValue;
        
        // Draw axes
        context.strokeStyle = '#ddd';
        context.lineWidth = 1;
        context.beginPath();
        context.moveTo(padding, padding);
        context.lineTo(padding, height - padding);
        context.lineTo(width - padding, height - padding);
        context.stroke();
        
        // Draw data points and lines
        context.strokeStyle = dataset.borderColor || '#007bff';
        context.lineWidth = dataset.borderWidth || 2;
        context.fillStyle = dataset.pointBackgroundColor || '#007bff';
        
        context.beginPath();
        points.forEach((value, index) => {
            const x = padding + (index / (points.length - 1)) * graphWidth;
            const y = height - padding - ((value - minValue) / valueRange) * graphHeight;
            
            if (index === 0) {
                context.moveTo(x, y);
            } else {
                context.lineTo(x, y);
            }
        });
        context.stroke();
        
        // Draw points
        points.forEach((value, index) => {
            const x = padding + (index / (points.length - 1)) * graphWidth;
            const y = height - padding - ((value - minValue) / valueRange) * graphHeight;
            
            context.beginPath();
            context.arc(x, y, 4, 0, 2 * Math.PI);
            context.fill();
        });
        
        // Draw labels
        context.fillStyle = '#666';
        context.font = '12px Arial';
        context.textAlign = 'center';
        labels.forEach((label, index) => {
            const x = padding + (index / (labels.length - 1)) * graphWidth;
            context.fillText(label, x, height - padding + 20);
        });
    };
    
    // Auto-render
    setTimeout(() => this.render(), 100);
};
